module.render:
const name = (args.name || 'f(x)').trim();
const delim = (args.delimiter || 'brace').toLowerCase();
const brace = delim === 'bracket' ? '[' : delim === 'none' ? '' : '{';
const colgap = (() => { const n = parseFloat(args.colgap); return Number.isFinite(n) && n >= 0 ? n : 20; })();
const bracesize = (args.bracesize && String(args.bracesize).trim()) || '2.6em';
let vars = `--cs-colgap:${colgap}px; --cs-brace-size:${bracesize};`;
if (args.condcolor && String(args.condcolor).trim()) vars += ` --cs-cond-color:${String(args.condcolor).trim()};`;
const rows = sections.map((s) => (s || '').trim()).filter(Boolean).map((s) => {
  const i = s.indexOf('|');
  return { val: (i >= 0 ? s.slice(0, i) : s).trim(), cond: i >= 0 ? s.slice(i + 1).trim() : '' };
});
let body = '';
rows.forEach((r) => {
  body += `<div class="mdp-cs-val">\n\n${r.val}\n\n</div><div class="mdp-cs-cond">\n\n${r.cond}\n\n</div>`;
});
const braceHtml = brace ? `<span class="mdp-cs-brace">${brace}</span>` : '';
return `\n\n<div class="mdp-mod-cases" style="${vars}"><span class="mdp-cs-lhs">\n\n\\( ${name} = \\)\n\n</span>${braceHtml}<div class="mdp-cs-rows">${body}</div></div>\n\n`;
